// 7-Segment Counter (0–9) with Button
// Common-Cathode 7-segment display
// Segments: a=D2, b=D3, c=D4, d=D5, e=D6, f=D7, g=D8
// Button: D9 (INPUT_PULLUP, active LOW)

const int segPins[7] = {2, 3, 4, 5, 6, 7, 8}; // a,b,c,d,e,f,g
const int btnPin = 9;

// Common-cathode segment patterns for digits 0-9
// Bit order: a,b,c,d,e,f,g
const byte digits[10] = {
  0b1111110, // 0: a,b,c,d,e,f
  0b0110000, // 1: b,c
  0b1101101, // 2: a,b,d,e,g
  0b1111001, // 3: a,b,c,d,g
  0b0110011, // 4: b,c,f,g
  0b1011011, // 5: a,c,d,f,g
  0b1011111, // 6: a,c,d,e,f,g
  0b1110000, // 7: a,b,c
  0b1111111, // 8: a,b,c,d,e,f,g
  0b1111011  // 9: a,b,c,d,f,g
};

int count = 0;
bool lastBtnState = HIGH;
unsigned long lastDebounceTime = 0;
const unsigned long debounceDelay = 50;

void showDigit(int n) {
  byte pattern = digits[n];
  for (int i = 0; i < 7; i++) {
    digitalWrite(segPins[i], (pattern >> (6 - i)) & 1);
  }
}

void setup() {
  for (int i = 0; i < 7; i++) {
    pinMode(segPins[i], OUTPUT);
  }
  pinMode(btnPin, INPUT_PULLUP);
  showDigit(0);
}

void loop() {
  bool reading = digitalRead(btnPin);

  if (reading != lastBtnState) {
    lastDebounceTime = millis();
  }

  if ((millis() - lastDebounceTime) > debounceDelay) {
    // Trigger on falling edge (button pressed)
    if (reading == LOW && lastBtnState == HIGH) {
      count = (count + 1) % 10;
      showDigit(count);
    }
  }

  lastBtnState = reading;
}

